  // Obtener productos existentes y combinar (sin duplicar por código)
  var existing = [];
  try{ existing = JSON.parse(localStorage.getItem('ferreos_prods') || '[]'); }catch(e){}
  
  var codigosExist = new Set(existing.map(function(p){return p.cod;}));
  var nuevos = PRODS_VILLA.filter(function(p){return !codigosExist.has(p.cod);});
  var maxId = existing.reduce(function(m,p){return Math.max(m,p.id||0);}, 0);
  nuevos.forEach(function(p,i){p.id = maxId + i + 1;});
  
  var todos = existing.concat(nuevos);
  localStorage.setItem('ferreos_prods', JSON.stringify(todos));
  console.log('✓ Productos cargados:', todos.length, '('+nuevos.length+' nuevos de Villaflores)');
  
  // 2. Cargar inventario Villaflores (existencias en 0, listas para capturar)
  var INV_KEY_STOCK = 'ferreos_inv_stock';
  var invStock = {};
  try{ invStock = JSON.parse(localStorage.getItem(INV_KEY_STOCK) || '{}'); }catch(e){}
  
  if(!invStock['suc14']){
    invStock['suc14'] = {};
    todos.forEach(function(p){
      if(!invStock['suc14'][p.id]){
        invStock['suc14'][p.id] = 0;
      }
    });
    localStorage.setItem(INV_KEY_STOCK, JSON.stringify(invStock));
    console.log('✓ Inventario Villaflores inicializado (suc14)');
  }
  
  alert('✅ Villaflores cargada:\n• '+nuevos.length+' productos nuevos\n• Inventario inicializado en 0\nRecarga la página para ver los cambios.');
  
